def sieve_of_eratosthenes(limit):
    """Eratosthenes algoritması ile limit'e kadar olan asal sayıları bulur."""
    sieve = [True] * (limit + 1)
    sieve[0:2] = [False, False]  # 0 ve 1 asal değildir
    for current_prime in range(2, int(limit**0.5) + 1):
        if sieve[current_prime]:
            for multiple in range(current_prime*2, limit + 1, current_prime):
                sieve[multiple] = False
    return [num for num, is_prime in enumerate(sieve) if is_prime]

def is_multiply_prime(a):
    """Verilen sayının üç asal sayının çarpımı olup olmadığını kontrol eder."""
    primes = sieve_of_eratosthenes(a)
    for i in range(len(primes)):
        if a % primes[i] == 0:
            remaining = a // primes[i]
            for j in range(i, len(primes)):
                if remaining % primes[j] == 0:
                    return remaining // primes[j] in primes
    return False

# Örnek kullanım
print(is_multiply_prime(30))  # True
print(is_multiply_prime(31))  # False
```

