def anti_shuffle(s):
    # Girdi dizgisini kelimelere ve boşluklara ayırma
    words_and_spaces = []
    word = ''
    for char in s:
        if char.isspace():
            if word:
                words_and_spaces.append(word)
                word = ''
            words_and_spaces.append(char)
        else:
            word += char
    if word:
        words_and_spaces.append(word)

    # Her kelimenin karakterlerini ASCII değerine göre sıralama
    ordered_words_and_spaces = []
    for item in words_and_spaces:
        if item.isspace():
            ordered_words_and_spaces.append(item)
        else:
            ordered_word = ''.join(sorted(item))
            ordered_words_and_spaces.append(ordered_word)

    # Kelimeleri ve boşlukları tekrar birleştirme
    return ''.join(ordered_words_and_spaces)
```

Örnek kullanım:

```python
print(anti_shuffle('Hi'))  # 'Hi'
print(anti_shuffle('hello'))  # 'ehllo'
print(anti_shuffle('Hello World!!!'))  # 'Hello !!!Wdlor'
```
